import sys, json

data = json.load(sys.stdin)
with open('after-cpm-packages.json', 'w') as f:
    json.dump(data, f, indent=2)

# Also load baseline for comparison
with open('baseline-packages.json') as f:
    baseline = json.load(f)

def extract(d):
    result = {}
    for p in d['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(data)

print('=== CHANGES ===')
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        print(f'  {k[0]}/{k[1]}: {bv} -> {av}')

print('=== UNCHANGED ===')
for k in sorted(b.keys()):
    if b[k] == a.get(k):
        print(f'  {k[0]}/{k[1]}: {b[k]}')
"

